const items = $input.all();
const ctx = $('Clean and Normalize Sender Email').item.json;
const EXAMPLE_USER_ID = 'SAMPLE_RECORD_ID';

const emailCtx = {
  senderEmail: String(ctx.senderEmail || ''),
  cleanedSenderEmail: String(ctx.cleanedSenderEmail || ''),
  leadMatchEmail: String(ctx.leadMatchEmail || ctx.cleanedSenderEmail || ''),
  extractedProspectEmail: String(ctx.extractedProspectEmail || ''),
  matchedViaExtractedEmail: ctx.matchedViaExtractedEmail === true,
  isSystemSender: ctx.isSystemSender === true,
  senderName: String(ctx.senderName || ''),
  subject: String(ctx.subject || ''),
  bodyPreview: String(ctx.bodyPreview || ''),
  emailBodyRaw: String(ctx.emailBodyRaw || ctx.emailBody || ctx.bodyPreview || ''),
  emailBody: String(ctx.emailBody || ctx.bodyPreview || ''),
  receivedDateTime: String(ctx.receivedDateTime || ''),
  internetMessageId: String(ctx.internetMessageId || ''),
  messageId: String(ctx.messageId || ''),
  inboxSource: String(ctx.inboxSource || ''),
  toRecipients: String(ctx.toRecipients || ''),
  ccRecipients: String(ctx.ccRecipients || '')
};

function ownerName(lead) {
  return String((lead.Owner && lead.Owner.Name) || lead['Owner.Name'] || '');
}
function ownerEmail(lead) {
  return String((lead.Owner && lead.Owner.Email) || lead['Owner.Email'] || '');
}

if (items.length > 0 && items[0].json && items[0].json.Id) {
  const lead = items[0].json;
  const matchedLeadOwnerId = String(lead.OwnerId || '').trim();
  const taskOwnerId = matchedLeadOwnerId || '';

  return [{ json: {
    leadFound: true,
    matchedLeadId: String(lead.Id || ''),
    matchedLeadName: String(lead.Name || ''),
    matchedLeadEmail: String(lead.Email || ''),
    matchedLeadOwnerId,
    matchedLeadOwnerName: ownerName(lead),
    matchedLeadOwnerEmail: ownerEmail(lead),
    taskOwnerId,
    ownerIdBlank: !matchedLeadOwnerId,
    leadId: String(lead.Id || ''),
    leadName: String(lead.Name || ''),
    leadStatus: String(lead.Status || ''),
    engagementStatus: String(lead.Engagement_Status__c || ''),
    leadEmail: String(lead.Email || ''),
    leadOwnerId: matchedLeadOwnerId,
    leadOwnerName: ownerName(lead),
    leadOwnerEmail: ownerEmail(lead),
    ...emailCtx
  }}];
}

return [{ json: {
  leadFound: false,
  matchedLeadId: null,
  matchedLeadName: null,
  matchedLeadEmail: emailCtx.leadMatchEmail,
  matchedLeadOwnerId: null,
  matchedLeadOwnerName: null,
  matchedLeadOwnerEmail: null,
  taskOwnerId: EXAMPLE_USER_ID,
  ownerIdBlank: false,
  leadId: null,
  leadName: null,
  leadStatus: null,
  engagementStatus: null,
  leadEmail: emailCtx.leadMatchEmail,
  leadOwnerId: null,
  leadOwnerName: null,
  leadOwnerEmail: null,
  ...emailCtx
}}];

const INTERNAL_DOMAINS = ['example.com'];
const SYSTEM_SENDER_PATTERNS = [
  'mailer-daemon', 'postmaster', 'noreply', 'no-reply', 'notifications@',
  'donotreply', 'do-not-reply', 'bounce', 'delivery', 'mail-daemon'
];
const EMAIL_REGEX = /[A-Z0-9._%+\-]+@[A-Z0-9.\-]+\.[A-Z]{2,}/gi;

function isInternalEmail(email) {
  const domain = String(email || '').split('@')[1] || '';
  return INTERNAL_DOMAINS.some((dom) => domain.toLowerCase() === dom);
}

function isSystemSender(email) {
  const lower = String(email || '').toLowerCase();
  return SYSTEM_SENDER_PATTERNS.some((pattern) => lower.includes(pattern));
}

function extractProspectEmail(subject, emailBody, bodyPreview, cleanedSenderEmail) {
  const haystack = [subject, emailBody, bodyPreview].join(' ');
  const matches = haystack.match(EMAIL_REGEX) || [];
  const seen = new Set();
  for (const raw of matches) {
    const email = String(raw).trim().toLowerCase();
    if (!email || seen.has(email)) continue;
    seen.add(email);
    if (email === cleanedSenderEmail) continue;
    if (isInternalEmail(email)) continue;
    if (isSystemSender(email)) continue;
    return email;
  }
  return '';
}

const results = [];
for (const item of $input.all()) {
  const d = item.json;
  const raw = (d.senderEmail || '').toString().trim();
  const matchAngle = raw.match(/<([^>]+)>/);
  const matchPlain = raw.match(/[A-Z0-9._%+\-]+@[A-Z0-9.\-]+\.[A-Z]{2,}/i);
  const cleanedSenderEmail = (matchAngle ? matchAngle[1] : matchPlain ? matchPlain[0] : raw).trim().toLowerCase();

  if (isInternalEmail(cleanedSenderEmail)) continue;

  const emailBodyRaw = String(d.emailBodyRaw || d.emailBody || d.bodyPreview || '').trim();
  const emailBody = String(d.emailBody || d.bodyPreview || '').trim();
  const subject = String(d.subject || '');
  const bodyPreview = String(d.bodyPreview || '');

  let leadMatchEmail = cleanedSenderEmail;
  let extractedProspectEmail = '';
  let matchedViaExtractedEmail = false;

  if (isSystemSender(cleanedSenderEmail)) {
    extractedProspectEmail = extractProspectEmail(subject, emailBody, bodyPreview, cleanedSenderEmail);
    if (extractedProspectEmail) {
      leadMatchEmail = extractedProspectEmail;
      matchedViaExtractedEmail = true;
    }
  }

  results.push({ json: {
    inboxSource: String(d.inboxSource || ''),
    senderEmail: String(d.senderEmail || ''),
    senderName: String(d.senderName || ''),
    subject,
    bodyPreview,
    emailBodyRaw,
    emailBody,
    receivedDateTime: String(d.receivedDateTime || ''),
    internetMessageId: String(d.internetMessageId || ''),
    messageId: String(d.messageId || ''),
    toRecipients: String(d.toRecipients || ''),
    ccRecipients: String(d.ccRecipients || ''),
    cleanedSenderEmail,
    leadMatchEmail,
    extractedProspectEmail,
    matchedViaExtractedEmail,
    isSystemSender: isSystemSender(cleanedSenderEmail)
  }});
}

return results.length > 0 ? results : [];

// Dedupe only flags duplicate reply TASK creation — does not block Lead/EST pause.
// Match on internetMessageId in existing task Description.
const ctx = $('Normalize Lead Match Result').item.json;
const EXAMPLE_USER_ID = 'SAMPLE_RECORD_ID';

const senderEmail = String(ctx.cleanedSenderEmail || '').toLowerCase().trim();
const leadEmail = String(ctx.matchedLeadEmail || ctx.leadEmail || '').toLowerCase().trim();
const internetMessageId = String(ctx.internetMessageId || '').trim();

let replyTaskAlreadyExists = false;
let existingTaskId = null;

if (internetMessageId) {
  try {
    const taskItems = $('Check Existing Reply Task').all();
    for (const item of taskItems) {
      const task = item && item.json;
      if (!task || !task.Id) continue;
      const description = String(task.Description || '');
      if (description.includes(internetMessageId)) {
        replyTaskAlreadyExists = true;
        existingTaskId = String(task.Id);
        break;
      }
    }
  } catch (e) {
    replyTaskAlreadyExists = false;
  }
}

const taskOwnerId = ctx.leadFound
  ? String(ctx.taskOwnerId || ctx.matchedLeadOwnerId || ctx.leadOwnerId || '')
  : String(ctx.taskOwnerId || EXAMPLE_USER_ID);

return [{ json: {
  alreadyProcessed: replyTaskAlreadyExists,
  replyTaskAlreadyExists,
  existingTaskId,
  skipReason: replyTaskAlreadyExists
    ? 'Reply task already created for this Message ID: ' + internetMessageId
    : '',
  emailMismatch: senderEmail !== leadEmail || !senderEmail,
  senderEmail, leadEmail,
  leadFound: ctx.leadFound === true,
  ownerIdBlank: ctx.ownerIdBlank === true,
  matchedLeadId: ctx.matchedLeadId ?? ctx.leadId ?? null,
  matchedLeadName: String(ctx.matchedLeadName || ctx.leadName || ''),
  matchedLeadEmail: String(ctx.matchedLeadEmail || ctx.leadEmail || ''),
  matchedLeadOwnerId: String(ctx.matchedLeadOwnerId || ctx.leadOwnerId || ''),
  matchedLeadOwnerName: String(ctx.matchedLeadOwnerName || ctx.leadOwnerName || ''),
  matchedLeadOwnerEmail: String(ctx.matchedLeadOwnerEmail || ctx.leadOwnerEmail || ''),
  taskOwnerId,
  leadId: String(ctx.leadId || ctx.matchedLeadId || ''),
  leadName: String(ctx.leadName || ctx.matchedLeadName || ''),
  leadStatus: String(ctx.leadStatus || ''),
  engagementStatus: String(ctx.engagementStatus || ''),
  leadEmail: String(ctx.leadEmail || ctx.matchedLeadEmail || ''),
  leadOwnerId: String(ctx.leadOwnerId || ctx.matchedLeadOwnerId || ''),
  leadOwnerName: String(ctx.leadOwnerName || ctx.matchedLeadOwnerName || ''),
  leadOwnerEmail: String(ctx.leadOwnerEmail || ctx.matchedLeadOwnerEmail || ''),
  cleanedSenderEmail: String(ctx.cleanedSenderEmail || ''),
  leadMatchEmail: String(ctx.leadMatchEmail || ctx.cleanedSenderEmail || ''),
  extractedProspectEmail: String(ctx.extractedProspectEmail || ''),
  matchedViaExtractedEmail: ctx.matchedViaExtractedEmail === true,
  isSystemSender: ctx.isSystemSender === true,
  senderName: String(ctx.senderName || ''),
  subject: String(ctx.subject || ''),
  bodyPreview: String(ctx.bodyPreview || ''),
  emailBodyRaw: String(ctx.emailBodyRaw || ctx.emailBody || ctx.bodyPreview || ''),
  emailBody: String(ctx.emailBody || ctx.bodyPreview || ''),
  receivedDateTime: String(ctx.receivedDateTime || ''),
  internetMessageId,
  messageId: String(ctx.messageId || ''),
  inboxSource: String(ctx.inboxSource || ''),
  toRecipients: String(ctx.toRecipients || ''),
  ccRecipients: String(ctx.ccRecipients || '')
}}];

const item = $input.first().json;

const normalizedText = (
  String(item.subject || '') + ' ' +
  String(item.emailBody || item.bodyPreview || '') + ' ' +
  String(item.senderName || '') + ' ' +
  String(item.senderEmail || '')
).toLowerCase();

const matchesAny = (patterns) => patterns.some((p) => normalizedText.includes(p));

const BOUNCE_PATTERNS = [
  'undeliverable', 'delivery has failed', 'delivery failure',
  'delivery status notification', 'mail delivery subsystem', 'returned mail',
  'failure notice', 'message blocked', 'address not found',
  'recipient address rejected', 'mailbox unavailable',
  "couldn't be delivered", 'could not be delivered', 'permanent failure',
  '550', '5.1.1', '5.4.1', 'postmaster', 'daemon'
];

const OOO_PATTERNS = [
  'out of office', 'automatic reply', 'auto-reply', 'auto reply', 'ooo',
  'away from the office', 'vacation', 'currently unavailable', 'autoresponder'
];

const CALENDAR_PATTERNS = [
  'accepted:', 'declined:', 'tentative:', 'meeting accepted', 'meeting declined',
  'calendar', 'invitation', 'updated invitation'
];

let replyClassification = 'human';

if (matchesAny(BOUNCE_PATTERNS)) {
  replyClassification = 'bounce';
} else if (matchesAny(OOO_PATTERNS)) {
  replyClassification = 'ooo';
} else if (matchesAny(CALENDAR_PATTERNS)) {
  replyClassification = 'calendar';
}

return [{ json: { ...item, replyClassification, normalizedText } }];

const dedupe = $('Normalize Dedupe Result').item.json;
const taskOwnerId = String(dedupe.taskOwnerId || dedupe.matchedLeadOwnerId || dedupe.leadOwnerId || '');
const expectedTaskOwnerName = String(dedupe.matchedLeadOwnerName || dedupe.leadOwnerName || '');
const leadOwnerId = String(dedupe.leadOwnerId || dedupe.matchedLeadOwnerId || '');
const leadOwnerName = String(dedupe.leadOwnerName || dedupe.matchedLeadOwnerName || '');
const leadId = String(dedupe.leadId || dedupe.matchedLeadId || '');
const leadName = String(dedupe.leadName || dedupe.matchedLeadName || '');
const subject = 'Prospect replied — respond within 24 hours';
const bodyText = String(dedupe.emailBody || '').trim() || String(dedupe.bodyPreview || '').trim();
const description = [
  'Prospect replied via email.',
  '',
  'AUTOMATION ACTION:',
  'Lead replied: Paused - human conversation',
  'This was classified as a real human reply.',
  'Lead Engagement Status was changed to: Paused - Human Conversation.',
  '',
  'Inbox Source: ' + (dedupe.inboxSource || 'unknown'),
  '',
  'To: ' + (dedupe.toRecipients || ''),
  'CC: ' + (dedupe.ccRecipients || 'none'),
  '',
  'From: ' + (dedupe.senderName || '') + ' <' + (dedupe.senderEmail || '') + '>',
  'Subject: ' + (dedupe.subject || ''),
  'Received: ' + (dedupe.receivedDateTime || ''),
  'Internet Message ID: ' + (dedupe.internetMessageId || ''),
  '',
  'Email Body:',
  bodyText
].join('\n');

return [{ json: {
  taskOwnerId,
  expectedTaskOwnerName,
  leadOwnerId,
  leadOwnerName,
  leadId,
  leadName,
  subject,
  description
}}];

const normalized = $("Normalize Example User's Email").item.json;
const msg = $input.first().json || {};
const emailBodyRaw = String(
  msg.body?.content || msg.body || normalized.emailBody || normalized.bodyPreview || ''
).trim();
function htmlToPlainText(html) {
  let text = String(html || '');
  if (!text) return '';
  text = text
    .replace(/<head[\s\S]*?<\/head>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '');
  text = text
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/(p|div|blockquote|li|tr|h[1-6])>/gi, '\n')
    .replace(/<[^>]+>/g, '');
  text = text
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&#(\d+);/g, (_, n) => String.fromCharCode(Number(n)));
  return text.replace(/\r\n/g, '\n').replace(/\n{3,}/g, '\n\n').trim();
}
const emailBody = htmlToPlainText(emailBodyRaw) || String(normalized.bodyPreview || '').trim();
return [{ json: { ...normalized, emailBodyRaw, emailBody } }];

