const cutoff = new Date('2025-06-15T00:00:00Z');
const results = [];

for (const item of $input.all()) {
  const received = new Date(item.json.receivedDateTime || '');
  if (Number.isNaN(received.getTime())) continue;
  if (received < cutoff) continue;
  results.push(item);
}

return results;
